import React, { useEffect, useState } from "react";

const TypingAnimation = () => {
  const [text, setText] = useState("");
  const textToType = "Bangar Raju";

  useEffect(() => {
    let currentIndex = 0;
    let isDeleting = false;
    const typingInterval = setInterval(() => {
      if (!isDeleting) {
        setText((prevText) => prevText + textToType[currentIndex]);
        currentIndex++;
        if (currentIndex === textToType.length) {
          isDeleting = true;
        }
      } else {
        setText((prevText) => prevText.slice(0, -1));
        currentIndex--;
        if (currentIndex === 0) {
          isDeleting = false;
        }
      }
    }, 200); // Adjust the interval value (in milliseconds) to control the typing speed

    return () => {
      clearInterval(typingInterval);
    };
  }, []);

  return (
    <b
      style={{
        textAlign: "left",
        fontSize: "40px",
        color: "white",
        // background: `linear-gradient(90deg, #e83e8c, #007bff)`,
        background: `linear-gradient(75deg, #007bff, #e83e8c)`,
        WebkitBackgroundClip: "text",
        WebkitTextFillColor: "transparent",
      }}
    >
      {text}
    </b>
  );
};

export default TypingAnimation;
